#ifndef __ASSEMBLER__
#define __ASSEMBLER__

typedef unsigned long long uint64;
// which hart is this?
static inline uint64 r_mhartid()
{
  uint64 x;
  asm volatile("csrr %0, mhartid" : "=r" (x) );
  return x;
}

// Machine Status Register, mstatus
#define MSTATUS_MPP_MASK (3L << 11) // previous mode.
#define MSTATUS_MPP_M (3L << 11)
#define MSTATUS_MPP_S (1L << 11)
#define MSTATUS_MPP_U (0L << 11)
#define MSTATUS_MIE (1L << 3)    // machine-mode interrupt enable.

static inline uint64 r_mstatus()
{
  uint64 x;
  asm volatile("csrr %0, mstatus" : "=r" (x) );
  return x;
}

static inline void  w_mstatus(uint64 x)
{
  asm volatile("csrw mstatus, %0" : : "r" (x) );
}

// machine exception program counter, 
// holds the instruction address to which 
// a return from exception will go.
static inline void w_mepc(uint64 x)
{
  asm volatile("csrw mepc, %0" : : "r" (x));
}

// Supervisor Status Register, sstatus
#define SSTATUS_SPP (1L << 8)  // Previous mode, 1=Supervisor, 0=User
#define SSTATUS_SPIE (1L << 5) // Supervisor Previous Interrupt Enable
#define SSTATUS_UPIE (1L << 4) // User Previous Interrupt Enable
#define SSTATUS_SIE (1L << 1)  // Supervisor Interrupt Enable
#define SSTATUS_UIE (1L << 0)  // User Interrupt Enable

static inline uint64 r_sstatus()
{
  uint64 x;
  asm volatile("csrr %0, sstatus" : "=r" (x) );
  return x;
}

static inline void w_sstatus(uint64 x)
{
  asm volatile("csrw sstatus, %0" : : "r" (x));
}

// Supervisor Interrupt Pending 中断挂起寄存器
static inline uint64 r_sip()
{
  uint64 x;
  asm volatile("csrr %0, sip" : "=r" (x) );
  return x;
}

static inline void w_sip(uint64 x)
{
  asm volatile("csrw sip, %0" : : "r" (x));
}

// Supervisor Interrupt Enable
#define SIE_SEIE (1L << 9) // external
#define SIE_STIE (1L << 5) // timer
#define SIE_SSIE (1L << 1) // software

static inline uint64 r_sie()
{
  uint64 x;
  asm volatile("csrr %0, sie" : "=r" (x) );
  return x;
}

static inline void w_sie(uint64 x)
{
  asm volatile("csrw sie, %0" : : "r" (x));
}

// Machine-mode Interrupt Enable
#define MIE_MEIE (1L << 11) // external
#define MIE_MTIE (1L << 7)  // timer
#define MIE_MSIE (1L << 3)  // software

static inline uint64 r_mie()
{
  uint64 x;
  asm volatile("csrr %0, mie" : "=r" (x) );
  return x;
}

static inline void w_mie(uint64 x)
{
  asm volatile("csrw mie, %0" : : "r" (x));
}

// supervisor exception program counter, holds the
// instruction address to which a return from
// exception will go.
static inline void w_sepc(uint64 x)
{
  asm volatile("csrw sepc, %0" : : "r" (x));
}

static inline uint64 r_sepc()
{
  uint64 x;
  asm volatile("csrr %0, sepc" : "=r" (x) );
  return x;
}

// Machine Exception Delegation
static inline uint64 r_medeleg()
{
  uint64 x;
  asm volatile("csrr %0, medeleg" : "=r" (x) );
  return x;
}

static inline void w_medeleg(uint64 x)
{
  asm volatile("csrw medeleg, %0" : : "r" (x));
}

// Machine Interrupt Delegation
static inline uint64 r_mideleg()
{
  uint64 x;
  asm volatile("csrr %0, mideleg" : "=r" (x) );
  return x;
}

static inline void w_mideleg(uint64 x)
{
  asm volatile("csrw mideleg, %0" : : "r" (x));
}

// Supervisor Trap-Vector Base Address
// low two bits are mode.
static inline void  w_stvec(uint64 x)
{
  asm volatile("csrw stvec, %0" : : "r" (x));
}

static inline uint64 r_stvec()
{
  uint64 x;
  asm volatile("csrr %0, stvec" : "=r" (x) );
  return x;
}

// Machine-mode interrupt vector
static inline void w_mtvec(uint64 x)
{
  asm volatile("csrw mtvec, %0" : : "r" (x));
}

// Physical Memory Protection
static inline void w_pmpcfg0(uint64 x)
{
  asm volatile("csrw pmpcfg0, %0" : : "r" (x));
}

static inline void w_pmpaddr0(uint64 x)
{
  asm volatile("csrw pmpaddr0, %0" : : "r" (x));
}

static inline void w_satp(uint64 x)
{
  asm volatile("csrw satp, %0" : : "r" (x));
}

static inline uint64 r_satp()
{
  uint64 x;
  asm volatile("csrr %0, satp" : "=r" (x) );
  return x;
}

static inline void w_mscratch(uint64 x)
{
  asm volatile("csrw mscratch, %0" : : "r" (x));
}

// Supervisor Trap Cause 
static inline uint64 r_scause()
{
  uint64 x;
  asm volatile("csrr %0, scause" : "=r" (x) );
  return x;
}

// Supervisor Trap Value
static inline uint64 r_stval()
{
  uint64 x;
  asm volatile("csrr %0, stval" : "=r" (x) );
  return x;
}

// Machine-mode Counter-Enable
static inline void w_mcounteren(uint64 x)
{
  asm volatile("csrw mcounteren, %0" : : "r" (x));
}

static inline uint64 r_mcounteren()
{
  uint64 x;
  asm volatile("csrr %0, mcounteren" : "=r" (x) );
  return x;
}

// machine-mode cycle counter
static inline uint64 r_time()
{
  uint64 x;
  asm volatile("csrr %0, time" : "=r" (x) );
  return x;
}

// enable S-MODE interrupts
static inline void intr_on()
{
  w_sstatus(r_sstatus() | SSTATUS_SIE);
}

// disable S-MODE interrupts
static inline void intr_off()
{
  w_sstatus(r_sstatus() & ~SSTATUS_SIE);
}

// are S-MODE interrupts enabled?
static inline int intr_get()
{
  uint64 x = r_sstatus();
  return (x & SSTATUS_SIE) != 0;
}

static inline uint64 r_sp()
{
  uint64 x;
  asm volatile("mv %0, sp" : "=r" (x) );
  return x;
}

// read and write tp, the thread pointer, which xv6 uses to hold
// this core's hartid (core number), the index into cpus[].
static inline uint64 r_tp()
{
  uint64 x;
  asm volatile("mv %0, tp" : "=r" (x) );
  return x;
}

static inline void w_tp(uint64 x)
{
  asm volatile("mv tp, %0" : : "r" (x));
}

static inline uint64 r_ra()
{
  uint64 x;
  asm volatile("mv %0, ra" : "=r" (x) );
  return x;
}

// flush the TLB.
static inline void sfence_vma()
{
  // the zero, zero means flush all TLB entries.
  asm volatile("sfence.vma zero, zero");
}

#endif // __ASSEMBLER__

/* memory leyout */
#ifndef __MEMLAYOUT_H__
#define __MEMLAYOUT_H__

// platform-level interrupt controller(PLIC)
#define PLIC_BASE 0x0c000000ul
#define PLIC_PRIORITY(id) (PLIC_BASE + (id) * 4)
#define PLIC_PENDING (PLIC_BASE + 0x1000)
#define PLIC_MENABLE(hart) (PLIC_BASE + 0x2000 + (hart)*0x100)
#define PLIC_SENABLE(hart) (PLIC_BASE + 0x2080 + (hart)*0x100)
#define PLIC_MPRIORITY(hart) (PLIC_BASE + 0x200000 + (hart)*0x2000)
#define PLIC_SPRIORITY(hart) (PLIC_BASE + 0x201000 + (hart)*0x2000)
#define PLIC_MCLAIM(hart) (PLIC_BASE + 0x200004 + (hart)*0x2000)
#define PLIC_SCLAIM(hart) (PLIC_BASE + 0x201004 + (hart)*0x2000)

// core local interruptor(CLINT)
#define CLINT_BASE 0x2000000ul
#define CLINT_MSIP(hartid) (CLINT_BASE + 4 * (hartid))
#define CLINT_MTIMECMP(hartid) (CLINT_BASE + 0x4000 + 8 * (hartid))
#define CLINT_MTIME (CLINT_BASE + 0xBFF8)

// virtio mmio
#define VIO_BASE  0x10001000ul
#define VIO_IRQ   1

// RTC 实时时钟
#define RTC_BASE  0x101000ul
#define TIMER_TIME_LOW  0x00
#define TIMER_TIME_HIGH 0x04

// UART
#define UART_BASE  0x10000000ul
#define UART_IRQ   10

// KERNEL
#ifdef visionfive
#define KERNEL_BASE  0x40200000ul
#else
#define KERNEL_BASE  0x80200000ul
#endif

/* 开发板使用 */
// sdcard地址
#define SDCARD_BEGIN 0x60000000

// 最大的虚拟地址
#define VA_MAX (1L << 38)

// 虚拟地址的最高处,占一个page,用户态和内核态共享的切换代码
#define TRAMPOLINE (VA_MAX - 4096)

// TRAMPOLINE下面, 内核态和用户态共享数据
#define TRAPFRAME (TRAMPOLINE - 4096)

// mmap的起点和终点
// 可分配区域大小为64MB (4096 * 16个物理页)
#define VM_MMAP_START (TRAPFRAME - 4096 * (4096 * 16 + 128))
#define VM_MMAP_END   (TRAPFRAME - 4096 * 128) 

// kernel stack 被映射到TRAMPOLINE下面的位置,占两个page
#define KSTACK(p) (TRAMPOLINE - ((p)+1)*2*4096)

// 对齐
#define ALIGN_UP(addr,refer) (((addr) + (refer) - 1) & ~((refer) - 1))
#define ALIGN_DOWN(addr,refer) ((addr) & ~((refer) - 1))

#endif

/* 物理内存管理 */

#include "lib/print.h"
#include "lib/str.h"
#include "mem/pmem.h"
#include "lock/lock.h"
#include "memlayout.h"

/*
--------------------------------- USER_END    (0x8800-0000)

// 可分配的用户数据区

--------------------------------- USER_BASE   (4KB对齐)

// 可分配的内核数据区 
(size = KERNEL_PAGE_NUM * 4KB)

--------------------------------- KERNEL_DATA (4KB对齐)

// 内核静态数据 (这里面包括了内核栈,在start.S中定义)

--------------------------------- KERNEL_TEXT (4KB对齐)

// 内核代码

--------------------------------- KERNEL_BASE (0x8000-2000)

// open-sbi的代码和数据

--------------------------------- Open_SBI    (0x8000-0000)

// 内存映射区域

---------------------------------
*/

uint64 USER_BASE;

#define KERNEL_PAGE_NUM 1024 // 4MB 内核空间

void* vio_mem; // 两个连续物理页，在virtio中使用

typedef struct listnode {
    struct listnode* next;
} listnode_t;

// 内核空闲页链表
struct {
    listnode_t freelist;
    spinlock_t lk;
} kmem;

// 用户空闲页链表
struct {
    listnode_t freelist;
    spinlock_t lk;
} umem;


// 物理内存初始化
void pmem_init(bool output)
{
    uint64 pa;
    listnode_t* node;

    spinlock_init(&kmem.lk, "kern mem");
    spinlock_init(&umem.lk, "user mem");
    kmem.freelist.next = NULL;
    umem.freelist.next = NULL;

    USER_BASE = KERNEL_TEXT + KERNEL_PAGE_NUM * PAGE_SIZE;

    // 内核空间 页链表的建立    
    spinlock_acquire(&kmem.lk);
    for(pa = KERNEL_DATA; pa < USER_BASE; pa += PAGE_SIZE) {
        node = (listnode_t*)pa;
        node->next = kmem.freelist.next;
        kmem.freelist.next = node;
    }
    spinlock_release(&kmem.lk);

    // 用户空间 页链表的建立
    spinlock_acquire(&umem.lk);
    for(pa = USER_BASE; pa < USER_END; pa += PAGE_SIZE) {
        node = (listnode_t*)pa;
        node->next = umem.freelist.next;
        umem.freelist.next = node;        
    }
    spinlock_release(&umem.lk);

    vio_mem = pmem_alloc_pages(1, true);
    pmem_alloc_pages(1, true);

    if(output) {
        printf("here is memlayout:\n");
        printf("kern_base = 0x0000-0000-8020-0000\n");
        printf("kern_text = %p\n",KERNEL_TEXT);
        printf("kern_data = %p\n",KERNEL_DATA);
        printf("user_base = %p\n",USER_BASE);
        printf("user_end  = 0x0000-0000-8800-0000\n");
        printf("pmem_init success!\n");
    }
}

/*
    申请npage个4K物理页
    成功返回物理页地址 失败返回NULL
*/
void* pmem_alloc_pages(int npages, bool in_kernel)
{
    assert(npages == 1, "pmem_alloc_pages\n");

    listnode_t* node;

    if(in_kernel) {
        spinlock_acquire(&kmem.lk);
        node = kmem.freelist.next;
        if(node) kmem.freelist.next = node->next;
        else kmem.freelist.next = NULL;
        spinlock_release(&kmem.lk);
    } else {
        spinlock_acquire(&umem.lk);
        node = umem.freelist.next;
        if(node) umem.freelist.next = node->next;
        else umem.freelist.next = NULL;
        spinlock_release(&umem.lk);
    }

    return (void*)node;
}
/*
    释放npages个物理页,从ptr指向的地址开始
*/
void pmem_free_pages(void* ptr, int npages, bool in_kernel)
{     
    assert(npages == 1, "pmem_free_pages: 1\n");
    assert((uint64)ptr % PAGE_SIZE == 0, "pmem_free_pages: 2\n");

    memset(ptr, 0, PAGE_SIZE);
    listnode_t* node = (listnode_t*)ptr;

    if(in_kernel) {

        assert((uint64)ptr >= KERNEL_DATA && (uint64)ptr < USER_BASE, "pmem_free_pages: 3\n");

        spinlock_acquire(&kmem.lk);
        node->next = kmem.freelist.next;
        kmem.freelist.next = node;
        spinlock_release(&kmem.lk);

    } else {

        assert((uint64)ptr >= USER_BASE && (uint64)ptr < USER_END, "pmem_free_pages: 4\n");

        spinlock_acquire(&umem.lk);
        node->next = umem.freelist.next;
        umem.freelist.next = node;
        spinlock_release(&umem.lk);

    }
}

#include "lib/str.h"
#include "lib/print.h"
#include "mem/pmem.h"
#include "mem/vmem.h"
#include "proc/cpu.h"
#include "dev/uart.h"
#include "memlayout.h"
#include "riscv.h"
#include "sbi.h"

pgtbl_t kernel_pagetable; // 指向内核页表

extern char trampoline[]; // in trampoline.S 

// 申请内核页表并完成一些基本映射
void kvm_init(void)
{
    // 申请L2内核页表空间
    kernel_pagetable = (pgtbl_t)pmem_alloc_pages(1, true);
    // printf("kernel pagetable = %p\n",kernel_pagetable);
    assert(kernel_pagetable != NULL, "kvm.c->kvm_init: 1\n");
    memset(kernel_pagetable, 0, PAGE_SIZE);

    int ret = 0;

#ifndef visionfive
    // uart寄存器映射
    ret += vm_mappages(kernel_pagetable, UART_BASE, UART_BASE, PAGE_SIZE, PTE_R | PTE_W);
    // virtio寄存器映射
    ret += vm_mappages(kernel_pagetable, VIO_BASE, VIO_BASE, PAGE_SIZE, PTE_R | PTE_W);
    // PLIC映射
    ret += vm_mappages(kernel_pagetable, PLIC_BASE, PLIC_BASE, 0x4000, PTE_R | PTE_W);
    ret += vm_mappages(kernel_pagetable, PLIC_BASE +  0x200000, PLIC_BASE +  0x200000, 0x4000, PTE_R | PTE_W);    
    // RTC实时时钟映射
    ret += vm_mappages(kernel_pagetable, RTC_BASE, RTC_BASE, PAGE_SIZE, PTE_R | PTE_W);
#endif

    // kernel代码区映射
    ret += vm_mappages(kernel_pagetable, KERNEL_BASE, KERNEL_BASE, KERNEL_TEXT-KERNEL_BASE, PTE_R | PTE_X | PTE_MACHINE);
    // kernel数据区映射
    ret += vm_mappages(kernel_pagetable, KERNEL_TEXT, KERNEL_TEXT, USER_END-KERNEL_TEXT, PTE_R | PTE_W | PTE_MACHINE);
    // trampoline映射
    ret += vm_mappages(kernel_pagetable, TRAMPOLINE, (uint64)trampoline, PAGE_SIZE, PTE_R | PTE_X | PTE_MACHINE);

#ifdef visionfive    
    // sdcard.img映射
    ret += vm_mappages(kernel_pagetable, SDCARD_BEGIN, SDCARD_BEGIN, 2ul * 1024ul * 1024ul * 1024, PTE_R | PTE_W | PTE_MACHINE);
#endif

    // 验证映射是否成功
    assert(ret == 0,"vmem.c->kvm_init 2\n");

    // 进程列表的内核栈映射
    proc_mapstacks(kernel_pagetable);
}

// 开启分页模式
void kvm_inithart(void)
{
    // flush the TLB
    // sfence_vma();
    // 写入内核页表,开启sv39模式的分页
    w_satp(MAKE_SATP(kernel_pagetable));    
    // flush the TLB
    sfence_vma();
}

// 调用SBI，命令所有核都执行tlb刷新命令
void vm_TLB_flush(uint64 va)
{
	va = ALIGN_DOWN(va, PAGE_SIZE);
	struct sbiret ret = SBI_RFENCE_SFENCE_VMA((1 << NCPU) - 1, 0, va, PAGE_SIZE);
	if (ret.error)
		panic("vm_TLB_flush fail");
}


// 根据pagetable,找到va对应的pte
// 若设置alloc=true 则在PTE无效时尝试申请一个物理页
// 成功返回PTE, 失败返回NULL
pte_t* vm_getpte(pgtbl_t pagetable, uint64 va, bool alloc)
{
    assert(va < VA_MAX, "kvm.c->vm_getpte\n");

    for(int level = 2; level > 0; level--) {

        // 在当前页表下,找到va对应的pte
        pte_t* pte = &pagetable[VA_TO_VPN(va, level)]; 

        if(*pte & PTE_V) {   // 有效PTE

            // 更新pagetable指向下一级页表
            pagetable = (pgtbl_t)PTE_TO_PA(*pte);

        } else if(alloc) {  // 无效PTE但是尝试申请

            // 申请一个物理页作为页表并清空
            pagetable = (pgtbl_t)pmem_alloc_pages(1, true);
            if(pagetable == NULL) return NULL;
            memset(pagetable, 0, PAGE_SIZE);

            // 修改PTE中的物理地址并设为有效
            *pte = PA_TO_PTE(pagetable) | PTE_V | PTE_MACHINE;

            vm_TLB_flush(va);

        } else {           // 无效且不尝试申请

            return NULL;

        }
    }

    return &pagetable[VA_TO_VPN(va, 0)];
}


// 在pagetable中建立映射 [va, va+len)->[pa, pa+len) 
// 映射是页面级的, 页面权限为perm
// pa 应当保证page-aligned, va 和 len 不需要保证
// 成功返回0, 失败返回-1
int vm_mappages(pgtbl_t pagetable, uint64 va, uint64 pa, uint64 len, int perm)
{
    assert(pa % PAGE_SIZE == 0,"veme.c->vm_mappages\n");

    // 确定映射范围
    uint64 first_page = ALIGN_DOWN(va, PAGE_SIZE);
    uint64 last_page  = ALIGN_DOWN(va+len-1, PAGE_SIZE);
    uint64 cur_page   = first_page;

    pte_t* pte;
    int count = 0;
    // 开始逐页映射

    while(cur_page <= last_page) {

        // 拿到pte并修改它
        pte = vm_getpte(pagetable, cur_page, true);
        if(pte == NULL) goto fail;
        *pte = PA_TO_PTE(pa) | perm | PTE_V | PTE_MACHINE;

        vm_TLB_flush(cur_page);

        // 迭代
        cur_page += PAGE_SIZE;
        pa       += PAGE_SIZE;
        count++; 
    }

    return 0;

fail:
    uvm_unmappages(pagetable, first_page, count, false);
    return -1;
}


// 数据复制: src->dst (len bytes)
// 如果目的地址是用户空间,执行uvm_copyout,否则执行memmove
// 成功返回0, 失败返回-1
int vm_copyout(bool usermode, uint64 dst, void* src, uint64 len)
{
    proc_t* proc = myproc();
    if(usermode) {
        return uvm_copyout(proc->pagetable, dst, (uint64)src, len);
    } else {
        memmove((char*)dst, src, len);
        return 0;
    }
}

// 数据复制: src->dst (len bytes)
// 如果源地址是用户空间,执行uvm_copyin,否则执行memmove
// 成功返回0, 失败返回-1
int vm_copyin(bool usermode, void* dst, uint64 src, uint64 len)
{
    proc_t* proc = myproc();
    if(usermode) {
        return uvm_copyin(proc->pagetable, (uint64)dst, src, len);
    } else {
        memmove(dst, (char*)src, len);
        return 0;
    }
}

