// trap全局初始化
void trap_init(void)
{
    timer_init();
}

// trap核心初始化
void trap_inithart(void)
{
    w_stvec((uint64)trap_vector);
    timer_setNext(false);
    intr_on(); // S态总中断开启
}

// 外设中断处理
void external_interrupt_handler()
{
    int irq = plic_claim();
    switch(irq) {
        case UART_IRQ:
            uart_intr();
            break;
        case VIO_IRQ:
            disk_intr();
            break;
        default:
            panic("unkown irq\n");
            break;
    }
    if(irq) plic_complete(irq);
}

