// 获取当前工作目录
// char* buf 用于存放工作目录的字符串
// int size  buf的大小
// 成功返回buf的指针, 失败返回NULL 
uint64 sys_getcwd()
{
    uint64 dst;
    int size;
    arg_addr(0, &dst);
    arg_int(1, &size);

    return FS_OP.fs_getcwd(dst, size);
}

// 切换工作目录
// char* path 要切换到的目录
// 成功返回0 失败返回-1
uint64 sys_chdir()
{
    char path[PATH_LEN];
    if(arg_str(0, path, PATH_LEN) < 0) 
        return -1;

    return FS_OP.fs_chdir(path);
}

// 按条目获取目录的内容
// int fd  要读取的目录名
// dirent_t* buf  保存目录信息的缓冲区
// int len  缓存区的大小
// 成功返回读取的字节数 失败返回-1 
uint64 sys_getdents64()
{

    int fd, size;
    uint64 dst;
    arg_int(0, &fd);
    if(fd != FD_CWD && (fd < 0 || fd >= NOFILE))
        return -1;
    arg_addr(1, &dst);
    arg_int(2, &size);

    return FS_OP.fs_getdents64(fd, dst, size);
}

// 创建目录文件
// int dirfd       要创建的目录文件所在目录的描述符
// char* path      要创建的目录文件的路径(规则见sys_read)
// mode_t mode     文件所有权(忽略)
// 成功返回0 失败返回-1
uint64 sys_mkdirat()
{
    int fd, mode;
    char path[PATH_LEN];
    path[PATH_LEN - 1] = '\0';

    arg_int(0, &fd);
    if(fd != FD_CWD && (fd < 0 || fd >= NOFILE))
        return -1;    
    if(arg_str(1, path, PATH_LEN - 1) < 0)
        return -1;
    arg_int(3, &mode);

    return FS_OP.fs_mkdirat(fd, path, (uint16)mode);
}

// 打开或创建一个文件
// int fd 文件所在目录的描述符
// char* path 目标文件的路径
// int flags 访问模式
// mode_t mode 文件所有权(暂时忽略)
// 1. 路径是绝对路径则忽略fd
// 2. 路径是相对路径且fd=-100   说明相对于cwd
// 3. 路径是相对路径且fd是合法值 说明相对于fd指向的路径
// 成功返回打开或创建的文件的描述符fd 失败返回-1 
uint64 sys_openat()
{
    int fd, flags, mode;   
    char path[PATH_LEN];
    path[PATH_LEN - 1] = '\0';

    arg_int(0, &fd);
    if(fd != FD_CWD && (fd < 0 || fd >= NOFILE))
        return -1;    
    if(arg_str(1, path, PATH_LEN - 1) < 0)
        return -1;
    arg_int(2, &flags);
    arg_int(3, &mode);

    return FS_OP.fs_openat(fd, path, flags, (uint16)mode);
}

