// 改变当前进程的堆数据区的大小
// uint64 va  希望当前数据区的堆顶变成va
// 成功返回0 失败返回-1
uint64 sys_brk()
{
    uint64 tar, cur; 

    arg_addr(0, &tar);
    cur = myproc()->sz;

    int n;
    if(tar == 0) {           // 这是一种查询
        return cur;
    } else if(tar > cur) {   // 申请更多地址空间
        n = (int)(tar - cur);
    } else {                 // 释放一些地址空间
        n = (int)(cur - tar);
        n = -n;
    }
    return proc_grow(n);
}

// 将文件或设备映射到内存中
// void* start   起始位置
// int len       字节长度
// int prot      映射的内存保护方式 EXEC READ WRITE NONE
// int flags     共享标志
// int fd        文件描述符
// int off       偏移量
// 成功返回已映射区域的指针, 失败返回-1
uint64 sys_mmap()
{
    uint64 start;
    int len, prot, fd, off, flags;

    arg_addr(0, &start);
    arg_int(1, &len);
    arg_int(2, &prot);
    arg_int(3, &flags);
    arg_int(4, &fd);
    arg_int(5, &off);

    return uvm_mmap(start, len, prot, flags, fd, off);
}

