// int prot
uint64 sys_mprotect()
{
    uint64 start;
    int len;
    int prot;

    arg_addr(0, &start);
    arg_int(1, &len);
    arg_int(2, &prot);

    assert(start % PAGE_SIZE == 0, "sys_mprotect: 0");

    return uvm_protect(start, len, prot);
} 

