{
    int clock_type;
    uint64 ts_addr;
    arg_int(0, &clock_type);
    arg_addr(1, &ts_addr);

    timespec_t ts = timer_get_ts(clock_type);
    if(uvm_copyout(myproc()->pagetable, ts_addr, (uint64)&ts, sizeof(ts)) < 0)
        return -1;
    return 0;
}

