#include "lib/print.h"

static struct ext4_raw_superblock sb;             // 磁盘里的super_block
static struct ext4_raw_group_desc gd[NGROUP];     // 磁盘里的group_desc

ext4_superblock_t ext4_sb;                        // 内存中的super_block
ext4_group_desc_t ext4_gd[NGROUP];                // 内存中的group_desc(假设只占一个block,不超过4096/32)

// ext4 文件系统初始化
// 填充 ext4_sb 和 ext4_gd
void ext4_init(uint32 dev, uint32 sb_sector)
{
	uint8* mem = pmem_alloc_pages(1, true);

	// 读取super_block
	// 注意: 第一个 4KB block 中 
	// 最先的 1KB 不可读取的引导部分
	// 后面的 1KB 是可以读取的超级块
	buf_t* buf = buf_read(dev, sb_sector);
	memmove(mem, buf->data, SECTOR_SIZE);
	buf_release(buf);

	buf = buf_read(dev, sb_sector + 1);
	memmove(mem + SECTOR_SIZE, buf->data, SECTOR_SIZE);
	buf_release(buf);

	memmove(&sb, mem, sizeof(sb));

	// 一些检查
	assert(sb.s_first_data_block == 0, "ext4_init: 0");
	assert(sb.s_log_block_size == 2, "ext4_init: 1");
	assert(sb.s_log_cluster_size == 2, "ext4_init: 2");
	assert(sb.s_magic == 0xEF53, "ext4_init: 3");
	assert(sb.s_state == 0x01, "ext4_init: 4");

	// 数据交接
	ext4_sb.block_count         = com(sb.s_blocks_count_lo, sb.s_blocks_count_hi);
	ext4_sb.inode_count         = sb.s_inodes_count;
	ext4_sb.block_per_group     = sb.s_blocks_per_group;
	ext4_sb.inode_per_group     = sb.s_inodes_per_group;
	ext4_sb.desc_size           = sb.s_desc_size;
	ext4_sb.inode_size          = sb.s_inode_size;
	ext4_sb.first_inode         = sb.s_first_inode;
	ext4_sb.reserved_gdt_blocks = sb.s_reserved_gdt_blocks;
	assert(ext4_sb.block_count == ext4_sb.block_per_group * NGROUP, "ext4_init: 5");

	// 读取group_desc
	ext4_block_read(dev, 1, 0, BLOCK_SIZE, mem, false);
	memmove(gd, mem, sizeof(gd));

	// 数据交接
	for(int i = 0; i < NGROUP; i++) {
		ext4_gd[i].block_bitmap     = (uint32)com(gd[i].bg_block_bitmap_lo, gd[i].bg_block_bitmap_hi);
		ext4_gd[i].inode_bitmap     = (uint32)com(gd[i].bg_inode_bitmap_lo, gd[i].bg_inode_bitmap_hi);
		ext4_gd[i].inode_table      = (uint32)com(gd[i].bg_inode_table_lo, gd[i].bg_inode_table_hi);
		ext4_gd[i].free_block_count = (uint32)com(gd[i].bg_free_blocks_count_lo,gd[i].bg_free_blocks_count_hi);
		ext4_gd[i].free_inode_count = (uint32)com(gd[i].bg_free_inodes_count_lo,gd[i].bg_free_inodes_count_hi);
	}

    ext4_inode_init(0);
	ext4_sys_init();
}

#include "fs/ext4.h"
#include "fs/ext4_raw.h"
#include "fs/ext4_inode.h"
#include "fs/ext4_block.h"
#include "fs/base_buf.h"
#include "syscall/sysproc.h"
#include "mem/pmem.h"
#include "lib/str.h"
#include "lib/print.h"

extern ext4_superblock_t ext4_sb;
extern ext4_group_desc_t ext4_gd[NGROUP];

/*
	ext4_rooti inodes[NFILE - 1] inodes[NFILE -2] ..... inodes[0]
	构成双向循环链表
	ext4_rooti.next是 使用中的inode
	ext4_rooti.prev是 未使用的inode
*/

ext4_inode_t ext4_rooti;

struct {
	spinlock_t lk;              // 这个锁保护双向循环链表的操作
	ext4_inode_t inodes[NFILE]; // inode集合
} ext4_itable;

// inode->imode => file->type
// 一一对应
uint8 mode_to_type(uint16 mode)
{
	uint8 type = TYPE_UNKNOWN;
	switch (mode & IMODE_MASK)
	{
		case IMODE_FILE:
			type = TYPE_REGULAR;
			break;
		case IMODE_DIR:
			type = TYPE_DIRECTORY;
			break;
		case IMODE_CHAR:
			type = TYPE_CHARDEV;
			break;
		case IMODE_BLOCK:
			type = TYPE_BLOCKDEV;
			break;
		case IMODE_FIFO:
			type = TYPE_FIFO;
			break;
		case IMODE_SOCK:
			type = TYPE_SOCKET;
			break;
		case IMODE_SYM:
			type = TYPE_SYMLINK;
			break;		
		default:
			break;
	}
	return type;
}

// itable和iroot初始化
void ext4_inode_init(uint32 dev)
{
	sleeplock_init(&ext4_rooti.lk, "ext4_inode root");
	ext4_rooti.par  = NULL;
	ext4_rooti.dev  = dev;
	ext4_rooti.ref  = 1;
	ext4_rooti.inum = 2;
	ext4_rooti.name[0] = '\0';
	ext4_rooti.path[0] = '/';
	ext4_rooti.next = &ext4_rooti;
	ext4_rooti.prev = &ext4_rooti;
	sleeplock_acquire(&ext4_rooti.lk);
	ext4_inode_readback(&ext4_rooti);
	sleeplock_release(&ext4_rooti.lk);

	spinlock_init(&ext4_itable.lk, "ext4_itable");	
	for(ext4_inode_t* ip = ext4_itable.inodes; ip < &ext4_itable.inodes[NFILE]; ip++) {
		sleeplock_init(&(ip->lk), "ext4_inode");
		ip->par = NULL;
		ip->dev = dev;
		ip->inum = 0;
		ip->ref = 0;
		ip->name[0] = '\0';
		ip->path[0] = '\0';

		ip->next = ext4_rooti.next;
		ext4_rooti.next->prev = ip;
		ip->prev = &ext4_rooti;
		ext4_rooti.next = ip;
	}
}

// 返回inode_table区域的一个sector序号
// 这个sector包括序号为inum的inode
static uint32 locate_sector(uint32 inum)
{
	int group = inum / ext4_sb.inode_per_group;
	int offset = inum % ext4_sb.inode_per_group;
	return ext4_gd[group].inode_table * SEC_PER_BLO + offset / INODE_PER_SEC;
}

// 使用磁盘中的inode更新内存中的 (读 inode table)
// 更新的内容包括: mode size nlink node
// 注意: 调用者需要对ip上锁; ip->inum 应被设置好
void ext4_inode_readback(ext4_inode_t* ip)
{
	assert(sleeplock_holding(&ip->lk), "ext4_inode_readback: 0");	
	assert((ip->ref >= 1) && (ip->inum != 0), "ext4_inode_readback: 1");

	struct ext4_raw_inode *rip;
	uint32 sector = locate_sector(ip->inum - 1);
	uint32 offset = ((ip->inum - 1) % INODE_PER_SEC) * sizeof(struct ext4_raw_inode);

	buf_t* buf = buf_read(ip->dev, sector);
	rip = (struct ext4_raw_inode*)(buf->data + offset);

	ip->mode = rip->i_mode;
	ip->size = com(rip->i_size_lo, rip->i_size_hi);
	ip->nlink = rip->i_links_count;
	memmove(&ip->node, rip->i_root_node, sizeof(ip->node));

	buf_release(buf);
}

// 使用内存中的inode更新磁盘中的 (写 inode table)
// 注意:调用者需要对ip上锁
void ext4_inode_writeback(ext4_inode_t* ip)
{
	assert(sleeplock_holding(&ip->lk), "ext4_inode_writeback: 0");	
	assert((ip->ref >= 1) && (ip->inum != 0), "ext4_inode_writeback: 1");

	struct ext4_raw_inode *rip;
	uint32 sector = locate_sector(ip->inum - 1);
	uint32 offset = ((ip->inum -1) % INODE_PER_SEC) * sizeof(struct ext4_raw_inode);

	buf_t* buf = buf_read(ip->dev, sector);
	rip = (struct ext4_raw_inode*)(buf->data + offset);

	rip->i_mode = ip->mode;
	rip->i_size_lo = (uint32)ip->size;
	rip->i_size_hi = (uint32)(ip->size >> 32);
	rip->i_links_count = ip->nlink;
	memmove(rip->i_root_node, &ip->node, sizeof(ip->node));

	buf_write(buf);
	buf_release(buf);
}

// 获得一个空闲inode (操作itable)
// ip->ref = 1 其他字段都没设置
ext4_inode_t* ext4_inode_get()
{	
	spinlock_acquire(&ext4_itable.lk);

	ext4_inode_t* ip = ext4_rooti.prev;
	assert(ip->ref == 0, "ext4_inode_get: 0"); // 确认这是一个可用的inode

	// 链表操作: ip离开当前位置, 成为rooti的下一个
	ip->prev->next = ip->next;
	ip->next->prev = ip->prev;
	ip->next = ext4_rooti.next;
	ext4_rooti.next->prev = ip;
	ip->prev = &ext4_rooti;
	ext4_rooti.next = ip;

	ip->ref = 1;

	spinlock_release(&ext4_itable.lk);
	return ip;
}

// ip->ref-- 
// 如果减到0, 则释放一个inode (操作 ext4_itable)
void ext4_inode_put(ext4_inode_t* ip)
{
	spinlock_acquire(&ext4_itable.lk);
	if(ip->ref == 1) {
		sleeplock_acquire(&ip->lk);
		spinlock_release(&ext4_itable.lk);

		// 磁盘里的删除
		if(ip->nlink == 0)
			ext4_inode_trunc(ip);

		// 内存里的删除
		ip->next->prev = ip->prev;
		ip->prev->next = ip->next;
		ip->prev = ext4_rooti.prev;
		ext4_rooti.prev->next = ip;
		ip->next = &ext4_rooti;
		ext4_rooti.prev = ip;

		ip->par = NULL;
		ip->inum = 0;
		ip->name[0] = 0;
		ip->path[0] = 0;

		sleeplock_release(&ip->lk);			
		spinlock_acquire(&ext4_itable.lk);
	}
	ip->ref--;
	spinlock_release(&ext4_itable.lk);
}

// 在itable里查询满足条件的inode
ext4_inode_t* ext4_inode_search(ext4_inode_t* pip, char* filename)
{
	ext4_inode_t* ip;

	spinlock_acquire(&ext4_itable.lk);
	for(ip = ext4_rooti.next; ip != &ext4_rooti;) {
		if(ip->ref == 0) { // 说明读到未使用的inode了
			ip = NULL;
			break;
		} else if((ip->par == pip) && (strncmp(filename, ip->name, EXT4_NAME_LEN) == 0)) {
			break;
		}
		ip = ip->next;
	}
	spinlock_release(&ext4_itable.lk);

	return ip;
}

// ip->ref++ with lock protect
ext4_inode_t* ext4_inode_dup(ext4_inode_t* ip)
{
	spinlock_acquire(&ext4_itable.lk);
	ip->ref++;
	spinlock_release(&ext4_itable.lk);

	return ip;
}

// 获得一个空闲的inum (操作inode_bitmap)
uint32 ext4_inode_inum_alloc(uint32 dev)
{	
	uint32 inum = 0;
