void ext4_file_close(ext4_file_t* file)
{
    spinlock_acquire(&file->lk);
    file->ref--;
    if(file->ref == 0) {
        if(file->file_type == TYPE_REGULAR || 
           file->file_type == TYPE_DIRECTORY || 
           file->file_type == TYPE_CHARDEV ||
           file->file_type == TYPE_SYMLINK) {
