/*
    buf是扇区sector(物理单元)的在内存的副本(还包括其他信息)
    buf层是磁盘管理的顶层,也是文件系统的底层
    将disk_rw包装为buf_read和buf_write
    标准操作流: buf_read => 修改buf->data => buf_write => buf_release
*/
#include "memlayout.h"
#include "fs/base_buf.h"
#include "dev/vio.h"
#include "lib/print.h"

// NBUF个buf组成的双向循环链表
struct {
    spinlock_t lk;    // buf_cache的锁
    buf_t bufs[NBUF]; // buf块的数组
    buf_t head;       // 头节点,不存储实际数据,只使用指针
} buf_cache;

// 初始化buf_cache:包括初始化锁和构造双向循环链表
void buf_init(void)
{
    spinlock_init(&buf_cache.lk,"buffer cache");
    buf_cache.head.prev = &buf_cache.head;
    buf_cache.head.next = &buf_cache.head;
    // 头插法构造双向循环链表
    for(buf_t* b = buf_cache.bufs; b < &buf_cache.bufs[NBUF]; b++) {
        b->next = buf_cache.head.next;
        b->prev = &buf_cache.head;
        sleeplock_init(&b->lk, "buffer");
        buf_cache.head.next->prev = b;
        buf_cache.head.next = b;
    }
}

/*
    根据dev和sector的信息搜寻buf,找到符合条件的就返回
    如果没有符合条件的,尝试返回一个ref_cnt=0的buf
    返回的buf是上了锁的
    在函数buffer_read中使用
*/
static buf_t* buffer_get(uint32 dev, uint32 sector)
{
    buf_t *b, *empty = NULL;

    spinlock_acquire(&buf_cache.lk);

    // 遍历查找符合条件的buf并返回
    for(b = buf_cache.head.next; b != &buf_cache.head; b = b->next) {
        if(b->dev == dev && b->sector == sector) {
            b->ref++;
            goto ret;      
        } else if(empty == NULL && b->ref == 0) {
            empty = b;
        }  
    }    
    // 返回一个空闲的buf
    b = empty;       
    if(b != NULL) {
        b->dev = dev;
        b->sector = sector;
        b->valid = false;
        b->ref = 1;
    }

ret:
    spinlock_release(&buf_cache.lk);
    // 在这一步, 如果这个buf被别的进程占用了, 当前进程会陷入睡眠
    if(b != NULL) sleeplock_acquire(&b->lk);
    return b;                 
}

/*
    根据dev和sector的信息在内存中找到对应buf或从磁盘中读入
    对buf上锁后返回,若失败则返回NULL
*/
buf_t* buf_read(uint32 dev, uint32 sector)
{
    buf_t* buf = buffer_get(dev, sector);
    assert(buf != NULL, "buf_read\n");
    if(buf->valid == false) {   // block在磁盘中
        disk_rw(buf, 0); // 读入buf中
        buf->valid = true;
    }
    return buf;
}

/*
    把buf的内容写回磁盘
    注意调用者须持有buf的锁
*/
void buf_write(buf_t* buf)
{
    assert(sleeplock_holding(&buf->lk), "buf.c->write\n");
    disk_rw(buf, 1);
}

/*
    当前进程释放buf块,ref-- (LRU算法实现)
*/
void buf_release(buf_t* buf)
{
    assert(buf != NULL, "buf_release: 1\n");
    // 释放buf的锁
    assert(sleeplock_holding(&buf->lk), "buf.c->release: 2\n");
    sleeplock_release(&buf->lk);

    spinlock_acquire(&buf_cache.lk);
    buf->ref--;
    // no one is waiting for it
    if(buf->ref == 0) {
        // buf从原来的位置中离开
        buf->next->prev = buf->prev;
        buf->prev->next = buf->next;
        // buf成为head的下一个,更易被使用
        buf->next = buf_cache.head.next; 
        buf->prev = &buf_cache.head;
        buf_cache.head.next->prev = buf;
        buf_cache.head.next = buf;
    }
    spinlock_release(&buf_cache.lk);
}

// driver for qemu's virtio disk device
// uses qemu's mmio interface to virtio

#include "riscv.h"
#include "memlayout.h"
#include "dev/virtio.h"
#include "dev/vio.h"
#include "lib/print.h"
#include "lib/str.h"
#include "lock/lock.h"
#include "mem/pmem.h"
#include "proc/proc.h"
#include "fs/base_buf.h"

extern void* vio_mem; // in pmem.c

// the address of virtio mmio register r
#define R(r) ((volatile uint32*)(VIO_BASE + (r)))
#define availOffset (sizeof(struct virtq_desc) * NUM)

// 虚拟的磁盘
static struct disk {
    struct virtq_desc*  desc;
    struct virtq_avail* avail;
    struct virtq_used*  used;
    char free[NUM];
    uint16 used_idx;

    struct {
        buf_t* b;
        char status;
    } info[NUM];
    struct virtio_blk_req ops[NUM];
    spinlock_t lk;
} disk;


void virtio_disk_init(void)
{
    spinlock_init(&disk.lk,"virtio_disk");

    assert(*R(VIRTIO_MMIO_MAGIC_VALUE) == 0x74726976, "virtio_disk->init: 1\n");
    assert(*R(VIRTIO_MMIO_VERSION) == 1, "virtio_disk->init: 2\n");
    assert(*R(VIRTIO_MMIO_DEVICE_ID) == 2, "virtio_disk->init: 3\n");
    assert(*R(VIRTIO_MMIO_VENDOR_ID) == 0x554d4551, "virtio_disk->init: 4\n");

    spinlock_acquire(&disk.lk);

    uint32 status = 0;
    // 重置设备
    *R(VIRTIO_MMIO_STATUS) = status;

    // 设置ACK位 OS识别到设备
    status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
    *R(VIRTIO_MMIO_STATUS) = status;

    // 设置DRIVER位 OS知道如何驱动设备
    status |= VIRTIO_CONFIG_S_DRIVER;
    *R(VIRTIO_MMIO_STATUS) = status;

    // 设置设备feature位 做设备状态协商
	uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
	features &= ~(1 << VIRTIO_BLK_F_RO);
	features &= ~(1 << VIRTIO_BLK_F_SCSI);
	features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
	features &= ~(1 << VIRTIO_BLK_F_MQ);
	features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
	features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
	features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
	*R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

    // 设置设备FEATURE_OK位 驱动不再接受新的工作特性
    // status |= VIO_CONFIG_S_FEATURES_OK;
    // *R(VIO_MMIO_STATUS) = status; 
    // assert(*R(VIO_MMIO_STATUS) & VIO_CONFIG_S_FEATURES_OK,"virtio_disk->init: 5\n");

    // 选择要使用的虚拟队列,将它的下标写入QUEUE_SEL
    *R(VIRTIO_MMIO_QUEUE_SEL) = 0;

    // 检查QUEUE_READY寄存器
    assert(*R(VIRTIO_MMIO_QUEUE_PFN) == 0, "virtio_disk->init: 6\n");

    // 读取队列支持的最大大小
    uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
    assert(max != 0, "virtio_disk->init: 7\n");
    assert(max >= NUM, "virtio_disk->init: 8\n");

    *R(VIRTIO_MMIO_PAGE_SIZE) = PAGE_SIZE;

    // 在内存中申请空白页存放三个虚拟队列
    disk.desc  = (void*)vio_mem;
    disk.avail = (void*)((uint64)disk.desc + availOffset);
    disk.used  = (void*)((uint64)disk.desc + PAGE_SIZE);
    assert((disk.desc!=NULL) && (disk.used!=NULL) , "virtio_disk->init: 9\n");
    memset(disk.desc, 0, PAGE_SIZE * 2);

    // 设置队列的大小
	*R(VIRTIO_MMIO_QUEUE_NUM) = NUM;
	// 设置Queue Align
	*R(VIRTIO_MMIO_QUEUE_ALIGN) = PAGE_SIZE;
	// 设置QUEUE PFN
	*R(VIRTIO_MMIO_QUEUE_PFN) = (uint64)disk.desc >> 12;

    // free数组初始化
    for(int i=0; i<NUM; i++) 
        disk.free[i] = 1;

    // 至此设备激活
    status |= VIRTIO_CONFIG_S_DRIVER_OK;
    *R(VIRTIO_MMIO_STATUS) = status;

    spinlock_release(&disk.lk);
}

static int alloc_desc()
{
    for(int i=0; i<NUM; i++) {
        if(disk.free[i]) {
            disk.free[i] = 0;
            return i;
        }
    }
    return -1;
}

static void free_desc(int id)
{
    assert((id < NUM) && (id >= 0), "vitrio_disk->free_desc: 1\n");
    assert(disk.free[id] == 0, "vitrio_disk->free_desc: 1\n");

    disk.desc[id].addr = 0;
    disk.desc[id].flags = 0;
    disk.desc[id].len = 0;
    disk.desc[id].next = 0;
    disk.free[id] = 1;

    // proc_wakeup(&disk.free[0]);
}

static void free_chain(int id)
{
    while(1) {
        int flags = disk.desc[id].flags;
        int next = disk.desc[id].next;
        free_desc(id);
        if(flags & VRING_DESC_F_NEXT) { 
            id = next;
        } else { 
            break;
        }
    }
}

static int alloc3_desc(int* idx)
{
    for(int i=0; i<3; i++) {
        idx[i] = alloc_desc();
        if(idx[i] < 0){
            for(int j=0; j<i; j++)
                free_desc(idx[j]);
            return -1;
        }
    }
    return 0;
}

void virtio_disk_rw(buf_t* buf, bool write)
{
    uint64 sector = buf->sector; // 计算出扇区号

    spinlock_acquire(&disk.lk);

    int idx[3];
    while(1) {
        if(alloc3_desc(idx) == 0) break;
        panic("virtio_disk_rw: 0\n");
    }

    struct virtio_blk_req* buf0 = &disk.ops[idx[0]];
    if(write) buf0->type = VIRTIO_BLK_T_OUT; // write the disk
    else buf0->type = VIRTIO_BLK_T_IN;  // read the disk
    buf0->reserved = 0;
    buf0->sector = sector;

    disk.desc[idx[0]].addr = (uint64)buf0;
    disk.desc[idx[0]].len = sizeof(struct virtio_blk_req);
    disk.desc[idx[0]].flags = VRING_DESC_F_NEXT;
    disk.desc[idx[0]].next = idx[1];

    disk.desc[idx[1]].addr = (uint64)buf->data;
    disk.desc[idx[1]].len = SECTOR_SIZE;
    if(write) disk.desc[idx[1]].flags = 0;
    else disk.desc[idx[1]].flags = VRING_DESC_F_WRITE;
    disk.desc[idx[1]].flags |= VRING_DESC_F_NEXT;
    disk.desc[idx[1]].next = idx[2];

    disk.info[idx[0]].status = 0xff;
    disk.desc[idx[2]].addr = (uint64)&disk.info[idx[0]].status;
    disk.desc[idx[2]].len = 1;
    disk.desc[idx[2]].flags = VRING_DESC_F_WRITE;
    disk.desc[idx[2]].next = 0;

    buf->disk = true;
    disk.info[idx[0]].b = buf;

    disk.avail->ring[disk.avail->idx % NUM] = idx[0];

    __sync_synchronize();
    disk.avail->idx++;
    __sync_synchronize();

    *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0;

    // Wait for virtio_disk_intr() to say request has finished.
    while (buf->disk == true)
        proc_sleep(buf, &disk.lk);

    disk.info[idx[0]].b = 0;
    free_chain(idx[0]);

    spinlock_release(&disk.lk);
}

void virtio_disk_intr()
{
    spinlock_acquire(&disk.lk);

    *R(VIRTIO_MMIO_INTERRUPT_ACK) = *R(VIRTIO_MMIO_INTERRUPT_STATUS) & 0x3;

    __sync_synchronize();

    while(disk.used->idx != disk.used_idx) {
        __sync_synchronize();
        int id = disk.used->ring[disk.used_idx % NUM].id;
        assert(disk.info[id].status == 0, "virtio_disk->intr: 1\n");
        buf_t* buf = disk.info[id].b;
        // disk is done with buf
        __sync_synchronize();
        assert(buf->disk == true, "virtio_disk->intr: 2\n");
        buf->disk = false;
        __sync_synchronize();
        proc_wakeup(buf);
        disk.used_idx++;
    }

    spinlock_release(&disk.lk);
}

// low-level driver routines for 16550a UART
#include "memlayout.h"
#include "dev/uart.h"
#include "dev/console.h"
#include "lock/lock.h"
#include "proc/proc.h"

#define RHR  0      // receive holding reg
#define THR  0      // transmit holding reg
#define IER  1      // interrupt enable reg
#define IER_RX_ENABLE   (1<<0)
#define IER_TX_ENABLE   (1<<1)
#define FCR  2      // FIFO control reg
#define FCR_FIFO_ENABLE (1<<0)
#define FCR_FIFO_CLEAR  (3<<1)
#define ISR  2      // interrupt status reg
#define LCR  3      // line control reg
#define LCR_EIGHT_BITS  (3<<0) // special mode to set word len
#define LCR_BAUD_LATCH  (1<<7) // special mode to set baud rate
#define LSR 5       // line status reg
#define LSR_RX_READY    (1<<0) // input is ready
#define LSR_TX_IDLE     (1<<5) // THR可以接受字符

#define UART_REG(reg)     ((volatile uint8 *)(UART_BASE + reg))
#define read_reg(reg)     (*(UART_REG(reg)))
#define write_reg(reg, v) (*(UART_REG(reg)) = (v))


#define UART_TX_SIZE 32
struct uart_tx {
    char buf[UART_TX_SIZE];
    uint64 r;
    uint64 w;
    spinlock_t lk;
} uart_tx;

extern volatile int panicked; // in lib/print.c


static void uart_start()
{
    char c;
    // buffer为空则退出
    while(uart_tx.r != uart_tx.w) {
        // THR不可接受字符则退出
        if( (read_reg(LSR) & LSR_TX_IDLE) == 0) break;
        // 从buf中读出一个字符
        c = uart_tx.buf[uart_tx.r++ % UART_TX_SIZE];
        // 通知写者有空位了
        proc_wakeup(&uart_tx.r);
        // 真正的传输过程
        write_reg(THR, c);
    }
}

void uart_init()
{
    write_reg(IER, 0x00); // 关闭中断

    write_reg(LCR, LCR_BAUD_LATCH); // 进入准备设置波特率的模式
    write_reg(0, 0x03); // LSB of baud rate of 38.4K
    write_reg(1, 0x00); // MSB of baud rate of 38.4K

    write_reg(LCR, LCR_EIGHT_BITS); //进入准备设置字长的模式,并设置为8bit

    write_reg(FCR, FCR_FIFO_ENABLE | FCR_FIFO_CLEAR); // 清空并使能FIFO队列

    write_reg(IER, IER_TX_ENABLE | IER_RX_ENABLE); // 使能收发队列

    spinlock_init(&uart_tx.lk, "uart"); 
}

void uart_putc(int c)
{
    spinlock_acquire(&uart_tx.lk);

    if(panicked) {for(;;);}  // 发生panic, 卡死在这里

    while(uart_tx.w == uart_tx.r + UART_TX_SIZE)   // tx队列已满,写者写入失败
        proc_sleep(&uart_tx.r, &uart_tx.lk);       // 等待读者去读

    // 写入buf
    uart_tx.buf[uart_tx.w++ % UART_TX_SIZE] = (char)c; 

    // 将buf里的内容通过uart传输出去
    uart_start();

    spinlock_release(&uart_tx.lk);
}

void uart_puts(char* s)
{
    while(*s) {
        uart_putc((int)(*s));
        s++;
    }
}

int uart_getc(void)
{
    if(read_reg(LSR) & 0x01) {
        return read_reg(RHR);
    } else {
        return -1;
    }
}

// uart 输入中断处理函数
void uart_intr(void)
{
    int c;
    while(1) {
        c = uart_getc();
        if(c == -1) break;
        else cons_intr(c);
    }

    spinlock_acquire(&uart_tx.lk);
    uart_start();
    spinlock_release(&uart_tx.lk);
}

// 带开关中断的uart_putc
void uart_putc_sync(int c)
{
    push_off();

    // 这两步检查是对THR写之前的必须操作
    if(panicked) {for(;;);}
    while ((read_reg(LSR) & LSR_TX_IDLE) == 0);
    write_reg(THR, c);

    pop_off();
}

