        uart_putc_sync('\b'); // 回退        aa|b
        uart_putc_sync(' ');  // 空格覆盖    aa |
        uart_putc_sync('\b'); // 回退        aa|
    } else {
        uart_putc_sync((char)c);
    }
#endif
}

