#include "memlayout.h"
#include "sbi.h"
#include "riscv.h"
#include "dev/timer.h"
#include "lib/print.h"

uint64 ticks;
spinlock_t ticks_lk;

// 获取硬件时钟(自启动以来的总滴答数)
// 一切时钟函数的基础
uint64 timer_mono_clock()
{
    uint64 n;
    asm volatile("rdtime %0" : "=r"(n));
    return n;
}

// 获取实时时钟
uint64 timer_rtc_clock()
{
    return timer_mono_clock() + (54 * 365 + 200) * 24 * 3600 * CLOCK_PER_SEC;
}

void timer_init()
{
    spinlock_init(&ticks_lk, "ticks");
    ticks = 0;
}

void timer_setNext(bool update)
{
    // 设置计时器，再过INTERVAL个滴答后触发时钟中断
    SBI_SET_TIMER(timer_mono_clock() + INTERVAL);
    // 更新ticks
    if(update) {
        spinlock_acquire(&ticks_lk);
        ticks++;
        spinlock_release(&ticks_lk);
    }
}

timeval_t timer_get_tv()
{
    timeval_t tv;
    uint64 clk = timer_rtc_clock();
    tv.sec = CLOCK_TO_SEC(clk);
    tv.usec = CLOCK_TO_USEC(clk) % USEC_PER_SEC;
    return tv;
}

#define CT_REALTIME  0   // 实时时钟
#define CT_MONOTONIC 1   // 累加时钟

timespec_t timer_get_ts(int clock_type)
{
    timespec_t ts;
    uint64 clocks = 0;
    if(clock_type == CT_REALTIME) {
        clocks = timer_rtc_clock();
    } else if(clock_type == CT_MONOTONIC) {
        clocks = timer_mono_clock();
    } else {
        panic("timer_get_ts: 0");
    }
    ts.sec = CLOCK_TO_SEC(clocks);
    ts.nsec = CLOCK_TO_NSEC(clocks) % NSEC_PER_SEC;
    return ts;
}

#include "signal/signal.h"
#include "mem/vmem.h"
#include "mem/pmem.h"
#include "proc/cpu.h"
#include "lib/str.h"

// 成功返回0 失败返回-1
uint64 sig_action(int signum, uint64 addr_act, uint64 addr_oldact)
{
    proc_t* p = myproc();

    if(signum < 1 || signum > NSIG) return -1;
    if((addr_act != 0) && (signum == SIGKILL || signum == SIGSTOP)) return -1;

    spinlock_acquire(&p->lk);
    if(addr_oldact != 0) {
        if(uvm_copyout(p->pagetable, addr_oldact, 
        (uint64)(&p->sigactions[signum]), sizeof(sigaction_t)) < 0) {
            spinlock_release(&p->lk);
            return -1;   
        }
    }
    if(addr_act != 0) {
        if(uvm_copyin(p->pagetable, (uint64)(&p->sigactions[signum]), 
        addr_act, sizeof(sigaction_t)) < 0) {
            spinlock_release(&p->lk);
            return -1;
        }
    }
    spinlock_release(&p->lk);
    return 0;
}

// 成功返回0 失败返回-1
uint64 sig_procmask(int how, uint64 addr_set, uint64 addr_oldset)
{
    proc_t* p = myproc();
    sigset_t set;    

    spinlock_acquire(&p->lk);

    if(addr_oldset != 0) {
        if(uvm_copyout(p->pagetable, addr_oldset, 
        (uint64)(&p->sig_set), sizeof(p->sig_set)) < 0) {
            spinlock_release(&p->lk);
            return -1;
        }
    }

    if(addr_set != 0) {
        if(uvm_copyin(p->pagetable, (uint64)&set, 
        addr_set, sizeof(p->sig_set)) < 0) {
            spinlock_release(&p->lk);
            return -1;
        }
        for(int i = 0; i < SIGSET_LEN; i++) {
            switch (how) 
            {
                case SIG_BLOCK:
                    p->sig_set.val[i] |= set.val[i];
                    break;
                case SIG_UNBLOCK:
                    p->sig_set.val[i] &= ~(set.val[i]);
                    break;
                case SIG_SETMASK:
                    p->sig_set.val[i] = set.val[i];
                    break;                
                default:
                    break;
            }
        }
    }

    p->sig_set.val[0] &= 1ul << SIGTERM | 1ul << SIGKILL | 1 << SIGSTOP;
    spinlock_release(&p->lk);
    return 0;
}

uint64 sig_return()
{
    proc_t* p = myproc();
    memmove(p->tf, p->sig_frame, sizeof(struct trapframe));
    pmem_free_pages(p->sig_frame, 1, true);
    p->sig_frame = NULL;
    return p->tf->a0;
}

