static spinlock_t ramdisk_lock;
static uint32 sector_max;

void ram_disk_init(void)
{
    sector_max = (2ul * 1024ul * 1024ul * 1024ul) / SECTOR_SIZE;
    spinlock_init(&ramdisk_lock, "ramdisk");
}

void ram_disk_rw(buf_t* buf, bool write)
{
    assert(buf && buf->sector < sector_max, "ram_disk_rw");
    spinlock_acquire(&ramdisk_lock);
    void* sector_addr = (void*)SDCARD_BEGIN + buf->sector * SECTOR_SIZE;
    if(write) {
        memmove(sector_addr, buf->data, SECTOR_SIZE);
    } else {
        memmove(buf->data, sector_addr, SECTOR_SIZE);
    }
    spinlock_release(&ramdisk_lock);
}

void ram_disk_intr()
{
    panic("ram_disk_intr");
}

// 实时时钟 (来自zhongtianos)
#include "dev/rtc.h"
#include "memlayout.h"

#define R(r) ((volatile uint32*)(RTC_BASE + (r)))


uint64 rtc_gettime()
{
    uint64 time_high, time_low, time;
    time_low  = *R(TIMER_TIME_LOW);
    time_high = *R(TIMER_TIME_HIGH);
    time = (time_high << 32) | time_low;
    return time;
}

OUTPUT_ARCH( "riscv" )
ENTRY( _entry )

SECTIONS
{
  /*
   * ensure that entry.S / _entry is at 0x80200000,
   * where qemu's -kernel jumps.
