  . = 0x80200000;

  .text : {
    *(.text .text.*)
    . = ALIGN(4K);
    *(trampsec)
    . = ALIGN(4K);
    PROVIDE(_KERNEL_TEXT = .);
  }

  .rodata : {
    . = ALIGN(16);
    *(.srodata .srodata.*)
    . = ALIGN(16);
    *(.rodata .rodata.*)
  }

  .data : {
    . = ALIGN(16);
    *(.sdata .sdata.*)
    . = ALIGN(16);
