    }

    .bss : {
        . = ALIGN(16);
        *(.sbss .sbss.*)
        . = ALIGN(16);
        *(.bss .bss.*)
    }

    PROVIDE(end = .);
}

// 第一个进程的内容
// 针对比赛要求逐个运行测试用例
// 这个文件参考了全年的二等奖作品: AVX 来自华中科技大学
// https://gitlab.eduxiji.net/202310487101114/oskernel2023-avx

#include "sys.h"

typedef struct {
  int valid;
  char *name[8];
} testcase;

static char* envp[] = {0};
static testcase time_test[];
static testcase busybox[];
static char* busybox_name[];
static testcase libctest_static[];
static testcase libctest_dynamic[];
static testcase lua[];
static testcase libc_bench[];

static int get_len(char* s)
{
    int i;
    for(i = 0; s[i] != '\0'; i++);
    return i;
}

int main()
{   
    int pid = 0;
    int ret = 0;

    // time-test
    syscall(SYS_write, 1, "run time-test\n", 14);
    pid = syscall(SYS_clone, 17, 0);
    if(pid < 0) {
        syscall(SYS_write, 1, "fork failed\n", 13);
        syscall(SYS_exit, 0);
    } else if(pid == 0) {  // 这里是新的进程
        syscall(SYS_execve,"./time-test" , time_test[0].name, envp);
        syscall(SYS_exit, 0);
    } else {               // 这里是旧的进程
        syscall(SYS_wait4, -1, 0);
    }

    // busybox-test
    syscall(SYS_write, 1, "run busybox_testcode.sh\n", 24);
    for(int i = 0; busybox[i].name[1]; i++) {
        pid = syscall(SYS_clone, 17, 0);
        if(pid < 0) {
            syscall(SYS_write, 1, "fork failed\n", 13);
            syscall(SYS_exit, 0);
        } else if(pid == 0) {  // 这里是新的进程
            ret = syscall(SYS_execve, "./busybox", busybox[i].name, envp);
            syscall(SYS_exit, 0);
        } else {               // 这里是旧的进程
            syscall(SYS_wait4, -1, 0);

            syscall(SYS_write, 1, "testcase busybox ", 17);
            syscall(SYS_write, 1, busybox_name[i], get_len(busybox_name[i]));
            if(ret == 0 || (ret != 0 && i == 12))
                syscall(SYS_write, 1, " success\n", 9);
            else
                syscall(SYS_write, 1, " fail\n", 6);
        }      
    }

    // libc-test
    syscall(SYS_write, 1, "run libctest_testcode.sh\n", 25);
    for(int i = 0; libctest_static[i].name[1]; i++) {
        if(libctest_static[i].valid == 0) continue;
        pid = syscall(SYS_clone, 17, 0);
        if(pid < 0) {
            syscall(SYS_write, 1, "fork failed\n", 13);
            syscall(SYS_exit, 0);
        } else if(pid == 0) {  // 这里是新的进程
            syscall(SYS_execve, "./runtest.exe", libctest_static[i].name, envp);
            syscall(SYS_exit, 0);
        } else {               // 这里是旧的进程
            syscall(SYS_wait4, -1, 0);
        }      
    }
    for(int i = 0; libctest_dynamic[i].name[1]; i++) {
        if(libctest_dynamic[i].valid == 0) continue;
        pid = syscall(SYS_clone, 17, 0);
        if(pid < 0) {
            syscall(SYS_write, 1, "fork failed\n", 13);
            syscall(SYS_exit, 0);
        } else if(pid == 0) {  // 这里是新的进程
            syscall(SYS_execve, "./runtest.exe", libctest_dynamic[i].name, envp);
            syscall(SYS_exit, 0);
        } else {               // 这里是旧的进程
            syscall(SYS_wait4, -1, 0);
        }      
    }

    syscall(SYS_write, 1, "run lua_testcode.sh\n", 20);
    for (int i = 0; lua[i].name[1]; i++) {
        if (!lua[i].valid) continue;
        pid = syscall(SYS_clone, 17, 0);
        if(pid < 0) {
            syscall(SYS_write, 1, "fork failed\n", 13);
            syscall(SYS_exit, 0);
        } else if(pid == 0) {  // 这里是新的进程
            ret = syscall(SYS_execve, "./lua", lua[i].name, envp);
            syscall(SYS_exit, 0);
        } else {               // 这里是旧的进程
            syscall(SYS_wait4, -1, 0);

            syscall(SYS_write, 1, "testcase lua ", 13);
            syscall(SYS_write, 1, lua[i].name[1], get_len(lua[i].name[1]));
            if(ret == 0)
                syscall(SYS_write, 1, " success\n", 9);
            else
                syscall(SYS_write, 1, " fail\n", 6);
        }      
    }

    // libc_bench
    syscall(SYS_write, 1, "run libc-bench\n", 15);
    pid = syscall(SYS_clone, 17, 0); 
    if(pid < 0) {
        syscall(SYS_write, 1, "fork failed\n", 13);
        syscall(SYS_exit, 0);
    } else if(pid == 0) {  // 这里是新的进程
        syscall(SYS_execve, "./libc-bench", libc_bench[0].name, envp);
        syscall(SYS_exit, 0);
    } else {               // 这里是旧的进程
        syscall(SYS_wait4, -1, 0);
    } 

    syscall(SYS_shutdown);
    return 0;
}

