// 字符串p的前n个字符与q做比较
// 按照ASCII码大小逐个比较
// 相同返回0 大于或小于返回正数或负数
int strncmp(const char *p, const char *q, uint32 n)
{
    while(n > 0 && *p && *p == *q)
      n--, p++, q++;
    if(n == 0)
      return 0;
    return (uint8)*p - (uint8)*q;
}

// 从src中复制前n个字符到dst
void strncpy(char *dst, const char *src, uint32 n)
{
    while(n != 0 && (*dst++ = *src++) != 0)
        n--;
    while(n !=0) {
        *dst++ = 0;
        n--;
    }
}

