// 验证用户地址合法性
static bool legal_addr(uint64 addr)
{
    proc_t* p = myproc();

    // 检查是否在用户空间 [0, sz)
    if(addr + sizeof(uint64) <= p->sz)
        return true;

    // 检查是否在 mmap 区域
    vm_region_t* vm = p->vm_head;
    while(vm != NULL) {
        if(vm->start <= addr && vm->start + PAGE_SIZE >= addr + sizeof(uint64))
            return true;
        vm = vm->next;
    }
    return false;
}
