**brk（调整堆大小）**：
```c
uint64 sys_brk()
{
    uint64 tar, cur;
    arg_addr(0, &tar);
    cur = myproc()->sz;

    if(tar == 0) {
        return cur;  // 查询当前堆顶
    }

    int n = (tar > cur) ? (int)(tar - cur) : -(int)(cur - tar);
    return proc_grow(n);
}
