#### 3.9.1 自旋锁

```c
typedef struct spinlock {
    uint32 locked;     // 0 = 未锁, 1 = 已锁
    char* name;        // 锁名称（调试用）
    int cpuid;         // 持有锁的 CPU
} spinlock_t;

void spinlock_acquire(spinlock_t* lk)
{
    push_off();  // 关闭中断（带计数）
    assert(!spinlock_holding(lk));  // 防止死锁

    // 原子交换：尝试获取锁
    while(__sync_lock_test_and_set(&lk->locked, 1) != 0)
        ;  // 自旋等待

    __sync_synchronize();  // 内存屏障
    lk->cpuid = mycpuid();
}

void spinlock_release(spinlock_t* lk)
{
    assert(spinlock_holding(lk));
    lk->cpuid = -1;
    __sync_synchronize();
    __sync_lock_release(&lk->locked);  // 原子释放
    pop_off();  // 恢复中断
}
```

**中断管理**：
```c
void push_off(void)
{
    int old = intr_get();
    intr_off();
    if(mycpu()->noff == 0)
        mycpu()->origin = old;  // 保存原始中断状态
    mycpu()->noff++;
}

void pop_off(void)
{
    cpu_t* cpu = mycpu();
    assert(intr_get() == 0);
    assert(cpu->noff >= 1);
    cpu->noff--;
    if(cpu->noff == 0 && cpu->origin == 1)
        intr_on();  // 恢复中断
}
```

#### 3.9.2 睡眠锁

```c
typedef struct sleeplock {
    spinlock_t lk;     // 保护锁本身的自旋锁
    uint32 locked;     // 0 = 未锁, 1 = 已锁
    int pid;           // 持有锁的进程 ID
    char* name;
} sleeplock_t;

void sleeplock_acquire(sleeplock_t* lock)
{
    spinlock_acquire(&lock->lk);
    while(lock->locked)
        proc_sleep(lock, &lock->lk);  // 睡眠等待
    lock->locked = 1;
    lock->pid = myproc()->pid;
    spinlock_release(&lock->lk);
}

void sleeplock_release(sleeplock_t* lock)
{
    spinlock_acquire(&lock->lk);
    lock->locked = 0;
    lock->pid = 0;
    proc_wakeup(lock);  // 唤醒等待进程
    spinlock_release(&lock->lk);
}
```

**设计特点**：
- 自旋锁用于短期临界区，睡眠锁用于长期临界区
- push_off/pop_off 支持嵌套关中断
- 锁持有者验证，防止错误释放

**不足之处**：
- 无读写锁支持
- 无优先级继承（可能导致优先级反转）

