#### 3.10.1 printf 实现

```c
int printf(const char* fmt, ...)
{
    va_list vl;
    bool flag = false;
    bool unsigned_flag = false;
    bool long_flag = false;

    va_start(vl, fmt);
    spinlock_acquire(&print_spinlock);

    for(int i = 0; fmt[i] != 0; i++) {
        char c = fmt[i];
        if(!flag) {
            if(c == '%') {
                flag = true;
            } else {
                uart_putc(c);
            }
            continue;
        }

        switch(c) {
            case 'u':
                unsigned_flag = true;
                break;
            case 'l':
                long_flag = true;
                break;
            case 'd':
                if(long_flag)
                    print_10(va_arg(vl, uint64), long_flag, unsigned_flag);
                else
                    print_10((uint64)(va_arg(vl, uint32)), long_flag, unsigned_flag);
                break;
            case 'x':
                print_16((uint64)(va_arg(vl, uint32)), false);
                break;
            case 'p':
                print_16(va_arg(vl, uint64), true);
                break;
            case 's':
                print_str(va_arg(vl, char*));
                break;
            case 'c':
                uart_putc((char)(va_arg(vl, int)));
                break;
        }
        flag = false;
    }

    spinlock_release(&print_spinlock);
    va_end(vl);
    return 0;
}
```

**支持的格式**：
- `%d` - int
- `%ld` - long long
- `%ud` - unsigned int
- `%uld` - unsigned long long
- `%x` - 十六进制 (32 位)
- `%p` - 十六进制 (64 位)
- `%c` - char
- `%s` - char*

